<template>
  <h3 class="title">Saved Workouts:</h3>
  <div class="saved-workouts-container">
    <h5 class="empty-workouts" v-if="workouts.length === 0">
      No workouts added
    </h5>
    <div class="saved-workouts">
      <ul>
        <li v-for="(workout, index) in workouts" :key="index">
          <h4 @click="showWorkouts(index)">{{ workout.date }}</h4>
          <p class="toShowWorkouts" v-if="!showWork">
            Click date to show workouts
          </p>
          <p class="showWorkouts" v-else>
            Workout: {{ workout.name }} - Reps: {{ workout.reps }} - Sets:
            {{ workout.sets }}
            <button @click="$emit('deleteWorkout', index)">X</button>
          </p>
        </li>
      </ul>
    </div>
  </div>
</template>

<script>
import { ref } from "@vue/reactivity";
export default {
  props: { workouts: Array },
  emits: ["deleteWorkout"],
  setup() {
    const showWork = ref(false);
    const showWorkouts = (index) => {
      console.log(index);
      showWork.value = !showWork.value;
    };

    return { showWork, showWorkouts };
  },
};
</script>

<style scoped>
.title {
  text-align: center;
  margin-top: 50px;
}
.saved-workouts-container {
  /*border: 1px solid black;*/
  display: flex;
  justify-content: center;
  align-items: center;
}
.empty-workouts {
  font-weight: 100;
  font-style: italic;
  font-size: 14px;
}
.saved-workouts h4 {
  padding: 10px;
  width: 85px;
  background-color: black;
  color: beige;
  border-radius: 10px;
  cursor: pointer;
}
.showWorkouts {
  /*border: 1px solid black;*/
  margin-top: -10px;
  padding: 10px;
  width: 400px;
  background-color: beige;
  border-radius: 5px;
}
.saved-workouts button {
  border: none;
  text-align: end;
  background-color: beige;
  cursor: pointer;
  font-size: 18px;
  font-weight: bold;
}
ul {
  list-style: none;
}

.toShowWorkouts {
  font-size: 12px;
  font-style: italic;
  padding: 10px;
  margin-left: -10px;
  margin-top: -20px;
}
</style>
